import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def centroid_position(customers):
        if customers:
            return np.mean(customers, axis=0)
        else:
            return depot_pos  # Return depot position if customer list is empty

    current_centroid = centroid_position(unvisited_customers) 

    def calculate_priority(midpoint, window_length, travel_time, arrival_time, distance_to_centroid):
        deviation = abs(midpoint - arrival_time)  
        return (deviation / window_length) + travel_time + (distance_to_centroid / len(unvisited_customers))

    best_node = None
    lowest_priority = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel
        start_window, end_window = time_windows[index]
        midpoint = (start_window + end_window) / 2
        window_length = end_window - start_window

        if start_window <= arrival_time <= end_window:  
            distance_to_centroid = np.linalg.norm(customer_pos - current_centroid)
            priority = calculate_priority(midpoint, window_length, travel, arrival_time, distance_to_centroid)

            if priority < lowest_priority:
                lowest_priority = priority
                best_node = index

    return best_node
